import Tesseract from 'tesseract.js';
import { jsPDF } from "jspdf";
import React, { useState, useEffect } from 'react';
import CrmLogoFull from './assets/logo.png';
import { supabase } from './supabaseClient';
import { 
  User, LogOut, Heart, Activity, Zap, Menu, X, 
  UserCircle, Clipboard, Save, Info, ChevronDown, ChevronRight,
  Plus, History, Folder, Moon, BookOpen, Bell, Lightbulb 
} from 'lucide-react';
import './Dashboard.css';

const HeartAnimation = "https://cdn-icons-png.flaticon.com/512/833/833472.png"; 
const KidneyAnimation = "https://cdn-icons-png.flaticon.com/512/2906/2906231.png";

const Dashboard = ({ user, onLogout }) => {
  // --- 1. STATE MANAGEMENT ---
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [isAnalysing, setIsAnalysing] = useState(false);
  const [showClinicalModal, setShowClinicalModal] = useState(false);
  const [showProfileModal, setShowProfileModal] = useState(false);
  const [selectedFiles, setSelectedFiles] = useState([]);
  const [mobileMenu, setMobileMenu] = useState(false);
  const [subMenus, setSubMenus] = useState({ health: false, reports: false });
  const [pastReports, setPastReports] = useState([]);
  const [selectedReport, setSelectedReport] = useState(null);

  const [formData, setFormData] = useState({
    age: '', weight: '', height: '', full_name: '',
    bp_sys: '', bp_dia: '', sugar: '', creatine: '',
    phone: '', address: '', gender: '',
    smoking: 'No', alcohol: 'No', activity: 'Sedentary',
    sleep: '', comorbidities: ''
  });

  // --- 2. DATA FETCHING ---
  const fetchReports = async () => {
    if (!user) return;
    try {
      const { data, error } = await supabase
        .from('reports')
        .select('*')
        .eq('user_id', user.id)
        .order('created_at', { ascending: false });
      if (error) throw error;
      setPastReports(data || []);
    } catch (err) { console.error("Vault Error:", err.message); }
  };

  const getProfile = async () => {
    if (!user) return;
    try {
      let { data, error } = await supabase.from('profiles').select('*').eq('id', user.id).single();
      if (data) {
        setProfile(data);
        setFormData(prev => ({ ...prev, ...data }));
      }
    } catch (err) { console.error("Profile Load Error:", err); } 
    finally { setLoading(false); }
  };

  useEffect(() => {
    if (user) { getProfile(); fetchReports(); }
  }, [user]);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const toggleSubMenu = (menu) => setSubMenus(prev => ({ ...prev, [menu]: !prev[menu] }));

  // --- 3. ANALYSIS ENGINE (Dual Reports & Pathology) ---
  const runAnalysisAndDownload = async () => {
    setIsAnalysing(true);
    let finalData = { ...formData };
    
    try {
      if (selectedFiles.length > 0) {
        const imageUrl = URL.createObjectURL(selectedFiles[0]);
        const { data: { text } } = await Tesseract.recognize(imageUrl, 'eng');
        URL.revokeObjectURL(imageUrl);
        const sugarMatch = text.match(/(?:glucose|sugar|glu)\D+(\d{2,3})/i);
        const creatineMatch = text.match(/(?:creatinine|crea)\D+(\d?\.?\d)/i);
        if (sugarMatch) finalData.sugar = sugarMatch[1];
        if (creatineMatch) finalData.creatine = creatineMatch[1];
      }

      const sanitizedData = {
        id: user.id, ...finalData,
        age: parseInt(finalData.age) || 0,
        bp_sys: parseInt(finalData.bp_sys) || 0,
        sugar: parseInt(finalData.sugar) || 0,
        creatine: parseFloat(finalData.creatine) || 0.0
      };
      const { data: updatedProfile } = await supabase.from('profiles').upsert(sanitizedData).select().single();
      setProfile(updatedProfile);

      // Pathology Logic
      const heartRisk = sanitizedData.bp_sys > 140 ? "High Risk" : "Stable";
      const kidneyRisk = sanitizedData.creatine > 1.2 ? "Elevated Stress" : "Optimal";
      
      // PDF 1: Full Diagnostic
      const doc1 = new jsPDF();
      doc1.setFillColor(15, 23, 42); doc1.rect(0, 0, 210, 45, 'F');
      doc1.setTextColor(255, 255, 255); doc1.text("FULL CLINICAL DIAGNOSTIC", 20, 25);
      doc1.save(`Full_Clinical_${Date.now()}.pdf`);

      // PDF 2: Snapshot
      const doc2 = new jsPDF();
      doc2.text("SYSTEMIC SNAPSHOT", 20, 20);
      doc2.save(`Quick_Snapshot_${Date.now()}.pdf`);

      const { data: savedReport } = await supabase.from('reports').insert([{
        user_id: user.id, report_name: `Analysis_${new Date().toLocaleDateString()}`,
        report_data: finalData, risk_score: heartRisk === "High Risk" ? 75 : 10
      }]).select();
      if (savedReport) setPastReports(prev => [savedReport[0], ...prev]);

      setShowClinicalModal(false);
      alert("Analysis Complete!");
    } catch (err) { alert(err.message); } finally { setIsAnalysing(false); }
  };

  if (loading) return <div className="status-screen">Initializing CRM...</div>;
  const bmi = profile?.height ? (profile.weight / (profile.height / 100) ** 2).toFixed(1) : '--';

  return (
    <div className="dashboard-container">
      <header className="dash-header">
        <div className="dash-nav-logo">
          <span className="logo-text">CRM Analysis</span>
          <img src={CrmLogoFull} alt="Logo" className="header-logo" />
        </div>
        <div className="nav-controls">
          <span className="user-welcome">Welcome, {profile?.full_name?.split(' ')[0] || 'User'}</span>
          <button className="mobile-menu-btn" onClick={() => setMobileMenu(!mobileMenu)}><Menu /></button>
        </div>
      </header>

      <div className="dash-main-wrapper">
        {/* SIDEBAR */}
        <aside className={`dash-sidebar ${mobileMenu ? 'active' : ''}`}>
          <div className="sidebar-header">
            <UserCircle size={50} color="#6366f1" />
            <h2 className="user-name">{profile?.full_name || "Patient"}</h2>
          </div>
          <nav className="sidebar-nav">
            <button className="nav-item active"><Activity size={18} /> Dashboard</button>
            <div className={`nav-group ${subMenus.health ? 'open' : ''}`}>
              <button className="nav-item-btn" onClick={() => toggleSubMenu('health')}>
                <Heart size={18} /> Health <span className="chevron-icon">{subMenus.health ? <ChevronDown size={14}/> : <ChevronRight size={14}/>}</span>
              </button>
              {subMenus.health && (
                <div className="sub-menu">
                  <button className="sub-link-btn" onClick={() => setShowClinicalModal(true)}><Plus size={14}/> Clinical Center</button>
                  <button className="sub-link-btn"><History size={14}/> Records</button>
                </div>
              )}
            </div>
            <button className="nav-item-btn" onClick={() => toggleSubMenu('reports')}>
              <Folder size={18} /> My Health Vault <span className="chevron-icon">{subMenus.reports ? <ChevronDown size={14}/> : <ChevronRight size={14}/>}</span>
            </button>
            {subMenus.reports && (
              <div className="sub-menu">
                {pastReports.length > 0 ? pastReports.map(r => (
                  <button key={r.id} className="sub-link-btn" onClick={() => setSelectedReport(r)}><BookOpen size={12}/> {r.report_name}</button>
                )) : <small style={{color:'#94a3b8', padding:'10px'}}>No reports</small>}
              </div>
            )}
            <button className="nav-item-btn" onClick={() => setShowProfileModal(true)}><Clipboard size={18} /> Update Profile</button>
            <button onClick={onLogout} className="sidebar-logout-btn"><LogOut size={16} /> Logout</button>
          </nav>
          <div className="sidebar-integrity-card">
            <div className="integrity-header"><Zap size={14} fill="currentColor" /> <span>System Integrity</span></div>
            <div className="integrity-body">
               <div className="integrity-item"><small>Encryption</small><div className="status-dot-active">AES-256</div></div>
               <div className="integrity-item"><small>Cloud Sync</small><div className="status-dot-active">Active</div></div>
            </div>
          </div>
        </aside>

        {/* MAIN CONTENT */}
        <main className="dash-content-area">
          <div className="content-header"><h1>Clinical Overview</h1></div>
          {profile && (
            <section className="user-profile-summary-card">
              <div className="profile-card-content">
                <div className="profile-main-info">
                  <h3>{profile.full_name}</h3>
                  <p>ID: {user.id.slice(0, 8)} | {profile.age} Yrs | {profile.gender}</p>
                </div>
                <div className="profile-tags">
                  <span className="p-tag">BP: {profile.bp_sys}/{profile.bp_dia}</span>
                  <span className="p-tag">Sugar: {profile.sugar} mg/dL</span>
                  <span className="p-tag lifestyle">Activity: {profile.activity}</span>
                  <span className="p-tag">Sleep: {profile.sleep}h</span>
                </div>
              </div>
            </section>
          )}

          <div className="crm-grid">
            <div className={`crm-status-box ${profile?.bp_sys > 140 ? 'status-critical' : ''}`}>
              <img src={HeartAnimation} className="crm-animated-icon" />
              <div className="crm-info"><h4>Cardiac</h4><div className="crm-reading">{profile?.bp_sys || '--'}/{profile?.bp_dia || '--'}</div></div>
            </div>
            <div className={`crm-status-box ${profile?.creatine > 1.2 ? 'status-critical' : ''}`}>
              <img src={KidneyAnimation} className="crm-animated-icon" />
              <div className="crm-info"><h4>Renal</h4><div className="crm-reading">{profile?.creatine || '--'}</div></div>
            </div>
            <div className={`crm-status-box ${profile?.sugar > 140 ? 'status-critical' : ''}`}>
              <div className="crm-icon-wrapper"><Zap size={30} color="#f59e0b" /></div>
              <div className="crm-info"><h4>Metabolic</h4><div className="crm-reading">{profile?.sugar || '--'}</div></div>
            </div>
          </div>

          <div className="lifestyle-row">
            <section className="lifestyle-card">
              <span className="card-main-title">Clinical Summary</span>
              <div className="main-metric-display">{profile?.age || '--'} <span className="metric-unit">Yrs</span></div>
              <p>Status: <strong>{profile?.bp_sys > 140 ? 'High Risk' : 'Stable'}</strong></p>
            </section>
            <section className="lifestyle-card">
              <span className="card-main-title">Body Composition</span>
              <div className="main-metric-display">{bmi} <span className="metric-unit">BMI</span></div>
              <p>{bmi > 25 ? 'Overweight Range' : 'Normal Range'}</p>
            </section>
          </div>

          <div className="reference-container">
            <div className="section-header-compact"><h3><BookOpen size={16} /> Clinical Reference Guide</h3></div>
            <div className="reference-grid">
              <div className="ref-card">
                <div className="ref-header"><Heart size={14} color="#ef4444" /> <span>Blood Pressure</span></div>
                <div className="ref-range-bar"><div className="current-marker" style={{left: `${Math.min((profile?.bp_sys/200)*100, 100)}%`}}></div></div>
                <div className="ref-labels"><small>Normal: &lt;120</small><small>High: 140+</small></div>
              </div>
              <div className="ref-card">
                <div className="ref-header"><Zap size={14} color="#f59e0b" /> <span>Blood Glucose</span></div>
                <div className="ref-range-bar"><div className="current-marker" style={{left: `${Math.min((profile?.sugar/200)*100, 100)}%`}}></div></div>
                <div className="ref-labels"><small>Normal: 70-100</small><small>High: 125+</small></div>
              </div>
              <div className="ref-card">
                <div className="ref-header"><Activity size={14} color="#10b981" /> <span>Creatinine</span></div>
                <div className="ref-range-bar"><div className="current-marker" style={{left: `${Math.min((profile?.creatine/2)*100, 100)}%`}}></div></div>
                <div className="ref-labels"><small>Normal: 0.7-1.3</small><small>High: 1.3+</small></div>
              </div>
            </div>
          </div>
        </main>

        {/* RIGHT PANEL */}
        <aside className="dash-right-panel">
          <div className="summary-card">
            <h3><Activity size={18} /> System Status</h3>
            <div className="status-mini-row">
              <span>Cardiac</span>
              <div className="mini-progress-bar"><div className="progress-fill" style={{width: `${Math.min((profile?.bp_sys/200)*100, 100)}%`}}></div></div>
            </div>
            <div className="right-panel-header"><Lightbulb size={16} color="#f59e0b" /> AI Health Forecasts</div>
            <div className="forecast-stack">
               <div className="forecast-item-card">
                  <div className="item-header"><Heart size={12} color="#ef4444" /> Cardiac Outlook</div>
                  <p>{profile?.bp_sys > 140 ? "High vascular resistance detected." : "Stable tension."}</p>
               </div>
            </div>
            <button className="btn-primary-save" style={{width:'100%', marginTop:'20px'}} onClick={() => setShowClinicalModal(true)}><Plus size={16}/> New Analysis</button>
          </div>
        </aside>
      </div>

      {/* CLINCAL MODAL (Unified 3-Section) */}
      {showClinicalModal && (
        <div className="modal-overlay">
          <div className="profile-modal-container unified-clinical-modal">
            <div className="modal-header-fixed"><h2>Clinical Intelligence Center</h2><button onClick={() => setShowClinicalModal(false)}><X/></button></div>
            <div className="modal-body-scroll">
              <div className="unified-grid profile-expanded-grid">
                <div className="clinical-form-side">
                  <h4 className="sub-section-title"><Activity size={14}/> Vitals</h4>
                  <div className="input-compact-grid">
                    <div className="field-group"><label>Systolic</label><input type="number" name="bp_sys" value={formData.bp_sys} onChange={handleInputChange} /></div>
                    <div className="field-group"><label>Diastolic</label><input type="number" name="bp_dia" value={formData.bp_dia} onChange={handleInputChange} /></div>
                  </div>
                  <div className="field-group" style={{marginTop:'10px'}}><label>Blood Sugar</label><input type="number" name="sugar" value={formData.sugar} onChange={handleInputChange} /></div>
                </div>
                  <div className="field-group" style={{marginTop:'10px'}}><label>Sugar</label><input type="number" name="sugar" value={formData.sugar} onChange={handleInputChange} /></div>
               
                <div className="clinical-form-side">
                  <h4 className="sub-section-title"><Zap size={14}/> Lifestyle</h4>
                  <div className="field-group"><label>Smoking</label><select name="smoking" value={formData.smoking} onChange={handleInputChange}><option value="No">No</option><option value="Yes">Yes</option></select></div>
                </div>
                <div className="clinical-form-side">
                  <h4 className="sub-section-title"><Folder size={14}/> Document Scan</h4>
                  <div className="compact-upload-zone" onClick={() => document.getElementById('f-up').click()}>
                    <Folder size={32} />
                    <input type="file" id="f-up" hidden onChange={(e)=>setSelectedFiles([e.target.files[0]])} />
                    <p>Click to Upload</p>
                    <small>{selectedFiles.length} files</small>
                  </div>
                </div>
              </div>
            </div>
            <div className="modal-footer-fixed"><button className="btn-primary-save" onClick={runAnalysisAndDownload} disabled={isAnalysing}>{isAnalysing ? "Syncing..." : "Run Analysis"}</button></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;
